(ns fix-test6
  (:require [clojure.string :as str]))

(let [content (slurp "test/datachannel/webrtc_integration_test.clj")
      target "                             (let [cand-info (sdp/parse-candidate (.sdp candidate))]\n                               (reset! remote-candidate-ip (:ip cand-info))\n                               (reset! remote-candidate-port (:port cand-info))\n                               (future\n                                 (loop [i 0]\n                                   (if @(:loop-future node)\n                                     (do\n                                       (datachannel.api/add-remote-candidate! node (:ip cand-info) (:port cand-info))\n                                       (println \"ADDED REMOTE CANDIDATE:\" (:ip cand-info) (:port cand-info)))\n                                     (when (< i 50) (Thread/sleep 100) (recur (inc i))))))))"
      new-target "                             (let [cand-info (sdp/parse-candidate (.sdp candidate))]\n                               (reset! remote-candidate-ip (:ip cand-info))\n                               (reset! remote-candidate-port (:port cand-info))\n                               (future\n                                 (loop [i 0]\n                                   (if @(:loop-future node)\n                                     (do\n                                       (datachannel.api/add-remote-candidate! node (:ip cand-info) (:port cand-info))\n                                       (println \"ADDED REMOTE CANDIDATE:\" (:ip cand-info) (:port cand-info)))\n                                     (when (< i 100) (Thread/sleep 50) (recur (inc i))))))))"]
  (spit "test/datachannel/webrtc_integration_test.clj" (str/replace content target new-target)))
